INSERT INTO contraindications (dci_pattern,condition_type,condition_valeur,severite,description,mecanisme_fr,conduite_fr)
VALUES
('fondaparinux','pathologie','HTA sévère non contrôlée (PA > 180/110 mmHg)','relative','Fondaparinux déconseillé en HTA sévère non contrôlée par risque d''AVC hémorragique','HTA sévère fragilise les vaisseaux. Anticoagulation par fondaparinux augmente le risque cérébral','Contrôler la PA avant anticoagulation. Évaluation neurologique si nécessaire'),
('fondaparinux','pathologie','Ulcère gastroduodénal actif','absolue','Fondaparinux contre-indiqué en ulcère actif : risque d''hémorragie digestive grave','Anticoagulation par fondaparinux (anti-Xa indirect) aggrave tout saignement sur lésion ulcéreuse','Traiter l''ulcère avant. IPP systématiques si anticoagulation indispensable'),
('fondaparinux','pathologie','AVC hémorragique récent (< 3 mois)','absolue','Fondaparinux formellement contre-indiqué après un AVC hémorragique récent','Risque majeur de récidive ou extension hémorragique cérébrale sous fondaparinux','CI absolue minimum 3 mois. Réévaluation neurologique après ce délai'),
('fondaparinux','pathologie','Endocardite bactérienne','relative','Fondaparinux expose à des emboles septiques hémorragiques en contexte d''endocardite','Végétations fragilisent l''endothélium. Anticoagulation augmente le risque d''AVC hémorragique','CI sauf valve mécanique. Héparine à objectif strict si indispensable'),
('fondaparinux','pathologie','Insuffisance hépatique sévère avec coagulopathie','absolue','Fondaparinux contre-indiqué en IHC sévère avec coagulopathie préexistante','Déficit de synthèse des facteurs coagulation hépatiques + fondaparinux → risque hémorragique extrême','CI absolue. Corriger coagulopathie. Avis hématologique obligatoire'),
('acénocoumarol','pathologie','Hémorragie active cliniquement significative','absolue','Acénocoumarol (AVK) formellement contre-indiqué en hémorragie active','Tout anticoagulant aggrave le saignement en cours par inhibition de la coagulation','Arrêt immédiat. Antagonisation si disponible. Prise en charge hémorragique urgente'),
('acénocoumarol','pathologie','Insuffisance rénale sévère (DFG < 30 mL/min)','relative','Acénocoumarol accumulé en insuffisance rénale sévère avec risque hémorragique majeur','Accumulation de acénocoumarol en cas d''insuffisance rénale','CI absolue pour AODs (DFG < 30). Préférer HNF si anticoagulation requise'),
('acénocoumarol','pathologie','Grossesse','absolue','Acénocoumarol (AVK) tératogène T1, hémorragique T2-T3','AVK traversent le placenta : embryopathie T1, hémorragie cérébrale fœtale T2-T3','HBPM recommandée pendant toute la grossesse comme alternative anticoagulante de référence'),
('acénocoumarol','pathologie','Chirurgie récente à haut risque hémorragique','absolue','Acénocoumarol contre-indiqué dans les suites immédiates d''une chirurgie à risque hémorragique élevé','Inhibition de la coagulation par acénocoumarol compromet l''hémostase chirurgicale','Respecter les délais post-opératoires selon le type de chirurgie et AVK'),
('acénocoumarol','pathologie','HTA sévère non contrôlée (PA > 180/110 mmHg)','relative','Acénocoumarol déconseillé en HTA sévère non contrôlée par risque d''AVC hémorragique','HTA sévère fragilise les vaisseaux. Anticoagulation par acénocoumarol augmente le risque cérébral','Contrôler la PA avant anticoagulation. Évaluation neurologique si nécessaire'),
('acénocoumarol','pathologie','Ulcère gastroduodénal actif','absolue','Acénocoumarol contre-indiqué en ulcère actif : risque d''hémorragie digestive grave','Anticoagulation par acénocoumarol (AVK) aggrave tout saignement sur lésion ulcéreuse','Traiter l''ulcère avant. IPP systématiques si anticoagulation indispensable'),
('acénocoumarol','pathologie','AVC hémorragique récent (< 3 mois)','absolue','Acénocoumarol formellement contre-indiqué après un AVC hémorragique récent','Risque majeur de récidive ou extension hémorragique cérébrale sous acénocoumarol','CI absolue minimum 3 mois. Réévaluation neurologique après ce délai'),
('acénocoumarol','pathologie','Endocardite bactérienne','relative','Acénocoumarol expose à des emboles septiques hémorragiques en contexte d''endocardite','Végétations fragilisent l''endothélium. Anticoagulation augmente le risque d''AVC hémorragique','CI sauf valve mécanique. Héparine à objectif strict si indispensable'),
('acénocoumarol','pathologie','Insuffisance hépatique sévère avec coagulopathie','absolue','Acénocoumarol contre-indiqué en IHC sévère avec coagulopathie préexistante','Déficit de synthèse des facteurs coagulation hépatiques + acénocoumarol → risque hémorragique extrême','CI absolue. Corriger coagulopathie. Avis hématologique obligatoire'),
('prednisone','pathologie','Infections fongiques systémiques','absolue','Prednisone contre-indiqué en infection fongique systémique active : dissémination fatale','Immunosuppression cortisonique favorise la dissémination des champignons','Antifongique systémique urgent. Arrêt ou réduction rapide du corticoïde'),
('prednisone','pathologie','Tuberculose active non traitée','absolue','Prednisone contre-indiqué en tuberculose active sans couverture antituberculeuse','Levée du contrôle immunitaire sur M. tuberculosis → dissémination miliaire possible','Antituberculeux au moins 2 semaines avant corticothérapie si indispensable'),
('prednisone','pathologie','Ulcère peptique actif','relative','Prednisone aggrave l''ulcère par réduction des prostaglandines et augmentation de l''acidité','Réduction des prostaglandines cytoprotectrices gastriques + hypersécrétion acide','IPP double dose systématique. Évaluer rapport bénéfice/risque. Traiter l''ulcère'),
('prednisone','pathologie','Diabète décompensé (glycémie > 3 g/L)','relative','Prednisone aggrave l''hyperglycémie par néoglucogenèse et résistance à l''insuline','Action anti-insulinique : néoglucogenèse hépatique ↑, captation périphérique glucose ↓','Contrôle glycémique strict avec adaptation insulinique. Glycémie quotidienne'),
('prednisone','pathologie','Ostéoporose sévère (T-score < -3)','relative','Prednisone aggrave l''ostéoporose par inhibition des ostéoblastes','Inhibition formation osseuse (ostéoblastes) + augmentation résorption (ostéoclastes)','Biphosphonate + vitamine D + calcium systématiques. DMO de suivi. Dose minimale'),
('prednisone','pathologie','Psychose aiguë ou antécédent de psychose cortisonique','relative','Prednisone peut déclencher ou aggraver une psychose cortisonique','Modification de la neurotransmission dopaminergique et sérotoninergique centrale','Évaluation psychiatrique préalable. Surveillance étroite. Dose minimale'),
('prednisone','pathologie','Glaucome à angle ouvert non contrôlé','relative','Prednisone élève la pression intraoculaire et aggrave le glaucome','Augmentation de la résistance à l''écoulement de l''humeur aqueuse dans le trabéculum','Surveillance ophtalmologique avec tonométrie régulière. Traitement antiglaucomateux'),
('prednisone','pathologie','Insuffisance cardiaque décompensée','relative','Prednisone provoque rétention hydrosodée aggravant l''insuffisance cardiaque','Action minéralocorticoïde : rétention sodium et eau → surcharge volémique','Restriction sodée stricte. Pesée quotidienne. Adapter les diurétiques'),
('prednisone','pathologie','Vaccination par vaccin vivant atténué','absolue','Prednisone contre-indique les vaccins vivants si dose immunosuppressive (≥ 10 mg/j > 2 sem)','Immunosuppression empêche le contrôle du virus vaccinal atténué → infection vaccinale','Vaccinations à jour avant corticothérapie prolongée. Éviter vaccins vivants sous corticoïdes'),
('prednisone','pathologie','Varicelle ou zona actif (patient non immunisé)','absolue','Prednisone contre-indiqué en varicelle chez adulte non immunisé : varicelle maligne','Immunosuppression empêche le contrôle du VZV → varicelle disséminée viscérale','Aciclovir IV en urgence. Immunoglobulines anti-VZV si exposé. Arrêt si possible'),
